#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
typedef long long LL;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int NQ=2e5+10,N=2e4+10;int head[N],des[N<<1],nxt[N<<1],cgt,n;LL a[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
struct Base
{	
	LL P[61];inline void clr(){memset(P,0,sizeof(P));}
	inline void ins(LL x){drep(60,0,i)if((x>>i)&1){if(P[i])x^=P[i];else return P[i]=x,void();}}
	inline LL qry(){LL res=0;drep(60,0,i)if(res<(res^P[i]))res^=P[i];return res;}
}rs[17][N],ans;
inline void merge(Base &a,const Base &b){rep(0,60,i)if(b.P[i])a.ins(b.P[i]);}
int fa[17][N],Lg[N],dep[N];
inline void dfs(const int &u=1,const int &f=0)
{
//	printf("%d\n",u);
	dep[u]=dep[fa[0][u]=f]+1;rs[0][u].ins(a[u]);
	rep(1,Lg[dep[u]],i)
	{
		fa[i][u]=fa[i-1][fa[i-1][u]];
		memcpy(rs[i][u].P,rs[i-1][u].P,sizeof(rs[i][u].P));
		merge(rs[i][u],rs[i-1][fa[i-1][u]]);
	}
	grep(u,i)if(des[i]!=f)dfs(des[i],u);
}
inline LL qry(int u,int v)
{
	memset(ans.P,0,sizeof(ans.P));if(dep[u]<dep[v]){int tmp=u;u=v;v=tmp;}
//	printf("U:: %d\n",u);
	drep(Lg[dep[u]-dep[v]+1],0,i){if(dep[fa[i][u]]>=dep[v]){merge(ans,rs[i][u]);u=fa[i][u];}}
//	printf("U:: %d\n",u);
	if(u==v){ans.ins(a[u]);return ans.qry();}
	drep(Lg[u],0,i)if(fa[i][u]!=fa[i][v])
	{
		merge(ans,rs[i][u]);merge(ans,rs[i][v]);
		u=fa[i][u];v=fa[i][v];
	}
	ans.ins(a[u]);ans.ins(a[v]);ans.ins(a[fa[0][u]]);return ans.qry();
}
int main() 
{
	
	n=read();int Q=read(); rep(1,n,i) Lg[i]=Lg[i>>1]+1,a[i]=read();
	rep(2,n,i)ins(read(),read());dfs(1); 	
	 while(Q--) printf("%lld\n",qry(read(),read()));
}
